//
//     final package = packageFromJson(jsonString);

import 'dart:convert';

Package packageFromJson(String str) => Package.fromJson(json.decode(str));

String packageToJson(Package data) => json.encode(data.toJson());

class Package {
    String name;
    String version;
    String description;
    String main;
    Engines engines;
    Dependencies dependencies;
    DevDependencies devDependencies;
    Scripts scripts;
    Repository repository;
    List<String> keywords;
    Browser browser;
    Nyc nyc;
    String license;

    Package({
        required this.name,
        required this.version,
        required this.description,
        required this.main,
        required this.engines,
        required this.dependencies,
        required this.devDependencies,
        required this.scripts,
        required this.repository,
        required this.keywords,
        required this.browser,
        required this.nyc,
        required this.license,
    });

    factory Package.fromJson(Map<String, dynamic> json) => Package(
        name: json["name"],
        version: json["version"],
        description: json["description"],
        main: json["main"],
        engines: Engines.fromJson(json["engines"]),
        dependencies: Dependencies.fromJson(json["dependencies"]),
        devDependencies: DevDependencies.fromJson(json["devDependencies"]),
        scripts: Scripts.fromJson(json["scripts"]),
        repository: Repository.fromJson(json["repository"]),
        keywords: List<String>.from(json["keywords"].map((x) => x)),
        browser: Browser.fromJson(json["browser"]),
        nyc: Nyc.fromJson(json["nyc"]),
        license: json["license"],
    );

    Map<String, dynamic> toJson() => {
        "name": name,
        "version": version,
        "description": description,
        "main": main,
        "engines": engines.toJson(),
        "dependencies": dependencies.toJson(),
        "devDependencies": devDependencies.toJson(),
        "scripts": scripts.toJson(),
        "repository": repository.toJson(),
        "keywords": List<dynamic>.from(keywords.map((x) => x)),
        "browser": browser.toJson(),
        "nyc": nyc.toJson(),
        "license": license,
    };
}

class Browser {
    bool util;
    bool workerThreads;
    String errors;
    String readableJs;
    String libInternalStreamsFromJs;
    String libInternalStreamsStreamJs;

    Browser({
        required this.util,
        required this.workerThreads,
        required this.errors,
        required this.readableJs,
        required this.libInternalStreamsFromJs,
        required this.libInternalStreamsStreamJs,
    });

    factory Browser.fromJson(Map<String, dynamic> json) => Browser(
        util: json["util"],
        workerThreads: json["worker_threads"],
        errors: json["./errors"],
        readableJs: json["./readable.js"],
        libInternalStreamsFromJs: json["./lib/internal/streams/from.js"],
        libInternalStreamsStreamJs: json["./lib/internal/streams/stream.js"],
    );

    Map<String, dynamic> toJson() => {
        "util": util,
        "worker_threads": workerThreads,
        "./errors": errors,
        "./readable.js": readableJs,
        "./lib/internal/streams/from.js": libInternalStreamsFromJs,
        "./lib/internal/streams/stream.js": libInternalStreamsStreamJs,
    };
}

